/**
 * Find matching profession based on job title
 * @param {string} jobTitle
 * @returns {object|null} matching profession or null
 */
export function matchProfession(jobTitle) {
  if (!jobTitle || !jobTitle.trim()) return null

  const normalizedTitle = jobTitle.toLowerCase().trim()

  for (const profession of SUMMARY_SUGGESTIONS) {
    for (const keyword of profession.keywords) {
      if (normalizedTitle.includes(keyword.toLowerCase()) || keyword.toLowerCase().includes(normalizedTitle)) {
        return profession
      }
    }
  }

  return null
}

/**
 * Get suggestions for a job title in the specified language
 * @param {string} jobTitle
 * @param {string} lang - 'ar' or 'en'
 * @returns {string[]} array of suggestion strings
 */
export function getSuggestions(jobTitle, lang = 'en') {
  const profession = matchProfession(jobTitle)
  if (!profession) return []

  return profession.summaries.map((s) => s[lang] || s.en)
}
